function jurina(x: number, y: number): string {
  let n: string = ""
  for (let a: number = 0; a < x; a++) {
    for (let b: number = 0; b < y; b++) {
      if (b % 3 == 2) {
        n = n + "I"
      } else if (b % 3 == 1) {
        n = n + "TSU"
      } else {
        n = n + "MA"
      }
      n = n + ""
    }
    n = n + "\n"
  }
  return n
}
